                        column += tabsize - column % tabsize;
                      else
                        break;
                    }
                  for (;; c2 = *t2++)
                    {
                      if (c2 == ' ')
                        column2++;
                      else if (c2 == '\t')
                        column2 += tabsize - column2 % tabsize;
                      else
                        break;
                    }
                  if (column != column2)
                    return true;
                }
              break;

            case IGNORE_NO_WHITE_SPACE:
              break;
            }

          /* Lowercase all letters if -i is specified.  */

          if (ignore_case)
            {
              c1 = tolower (c1);
              c2 = tolower (c2);
            }

          if (c1 != c2)
